    matrix* n = zeroMatrix(2,2);
    setMatrixElement(n,0,0,1);
    setMatrixElement(n,0,1,(axis) ? k : 0);
    setMatrixElement(n,1,0,(axis) ? 0 : k);
    setMatrixElement(n,1,1,1);
