    vector* v = nullVector(cols);
    fillVector(&v, 0);
    return v;
}
void fillVector(vector** v, double n){
    assertVector(*v);
    for(int i = 0; i < (*v)->cols; i++){
        (*v)->data[i] = n;
    }
}
