    free(v->data);
    v->data = NULL;
    free(v);
    v = NULL;
}
vector* copyVector(vector* v){
    assertVector(v);
    vector* c = zeroVector(v->cols);
    for(int i = 0; i < v->cols; i++){
        c->data[i] = v->data[i];
    }
    return c;
}
